sys_script_include.script:
var CertificateGenerator = Class.create();

CertificateGenerator.prototype = {

    initialize: function() {
    },

    generate: function(applicationId) {

        var cert = new GlideRecord('x_2059455_intern_0_certificates');

        cert.initialize();

        cert.u_application = applicationId;

        cert.u_certificate_number = "CERT" + new GlideDateTime().getNumericValue();

        cert.u_certificate_status = "Generated";

        cert.u_issue_date = gs.nowDate();

        return cert.insert();

    },

    type: 'CertificateGenerator'
};
